import json
import os
from collections import defaultdict

import psycopg

conn = psycopg.connect(
    host=os.getenv("DB_HOST", "127.0.0.1"),
    port=int(os.getenv("DB_PORT", "5432")),
    user=os.getenv("DB_USER", "ai"),
    password=os.getenv("DB_PASS", "ai"),
    dbname=os.getenv("DB_DATABASE", "ai"),
)

def iter_user_messages(runs):
    if not runs:
        return
    for run in runs:
        if not isinstance(run, dict):
            continue
        # common agno shapes
        for key in ("input", "content", "message"):
            val = run.get(key)
            if isinstance(val, str) and val.strip():
                yield val.strip()[:200]
        messages = run.get("messages") or run.get("history")
        if isinstance(messages, list):
            for m in messages:
                if not isinstance(m, dict):
                    continue
                role = (m.get("role") or "").lower()
                if role in ("user", "human"):
                    content = m.get("content")
                    if isinstance(content, str) and content.strip():
                        yield content.strip()[:200]
                    elif isinstance(content, list):
                        for part in content:
                            if isinstance(part, dict) and part.get("type") == "text":
                                t = part.get("text", "")
                                if t.strip():
                                    yield t.strip()[:200]

with conn.cursor() as cur:
    cur.execute(
        """
        SELECT session_id, user_id, metadata, session_data, runs, created_at
        FROM ai.agno_sessions
        WHERE team_id = 'concierge-team'
        ORDER BY created_at
        """
    )
    rows = cur.fetchall()

users = defaultdict(lambda: {"sessions": [], "first_msg": None, "msg_count": 0})
no_user_chatted = []
scheduler_sessions = []

for session_id, user_id, metadata, session_data, runs, created_at in rows:
    uid = user_id or "(anonymous)"
    if user_id == "__scheduler__":
        scheduler_sessions.append(session_id)
        continue

    msgs = list(iter_user_messages(runs))
    has_user_chat = len(msgs) > 0

    # try metadata/session_data for email
    email = None
    for blob in (metadata, session_data):
        if isinstance(blob, dict):
            email = email or blob.get("email") or blob.get("user_email")
            u = blob.get("user") or blob.get("user_info")
            if isinstance(u, dict):
                email = email or u.get("email")

    if has_user_chat:
        key = user_id or email or f"anonymous:{session_id[:8]}"
        rec = users[key]
        rec["sessions"].append(session_id)
        rec["msg_count"] += len(msgs)
        if rec.get("email") is None and email:
            rec["email"] = email
        if rec.get("user_id") is None and user_id:
            rec["user_id"] = user_id
        if rec["first_msg"] is None:
            rec["first_msg"] = msgs[0]
    elif user_id and user_id not in ("__scheduler__",):
        users[user_id]["sessions"].append(session_id)
        users[user_id].setdefault("user_id", user_id)

print("=== Concierge chat analysis ===")
print(f"Total sessions: {len(rows)}")
print(f"Scheduler sessions (excluded): {len(scheduler_sessions)}")
print()

# Real users with identifiable ids
real = {k: v for k, v in users.items() if k not in ("(anonymous)",) and not str(k).startswith("anonymous:")}
anon = {k: v for k, v in users.items() if str(k).startswith("anonymous:") or k == "(anonymous)"}

print(f"Identified users with chat: {len(real)}")
for k, v in sorted(real.items(), key=lambda x: -len(x["sessions"])):
    print(f"\n  User: {k}")
    if v.get("email"):
        print(f"    email (metadata): {v['email']}")
    print(f"    sessions: {len(v['sessions'])}")
    print(f"    user messages (approx): {v.get('msg_count', 0)}")
    if v.get("first_msg"):
        print(f"    first message snippet: {v['first_msg']!r}")

print(f"\nAnonymous/unauthenticated sessions with user messages: {len(anon)}")
for k, v in list(sorted(anon.items(), key=lambda x: -len(x[1]["sessions"])))[:5]:
    print(f"  {k}: {len(v['sessions'])} sessions, ~{v.get('msg_count',0)} msgs")
if len(anon) > 5:
    print(f"  ... and {len(anon)-5} more anonymous keys")

conn.close()
